example.code:
import { vi, describe, it, expect, afterEach } from 'vitest';
import { sendEmail } from '../adapters/email';
import { registerUser } from '../services/user';

vi.mock('../adapters/email');
afterEach(() => vi.clearAllMocks());

it('sends welcome email', async () => {
  await registerUser({ email: 'new@example.com' });
  expect(sendEmail).toHaveBeenCalledOnce();
  expect(sendEmail).toHaveBeenCalledWith(expect.objectContaining({ to: 'new@example.com' }));
});

type Mailer interface { Send(to, subject, body string) error }

type mockMailer struct{ calls []string }
func (m *mockMailer) Send(to, _, _ string) error { m.calls = append(m.calls, to); return nil }

func TestRegister(t *testing.T) {
    mailer := &mockMailer{}
    NewUserService(mailer).Register("user@x")
    if len(mailer.calls) != 1 { t.Errorf("want 1 call, got %d", len(mailer.calls)) }
}
